  ('dietitian-moex-08794', 'dietitian', 'dietitian-moex-098-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '當開立燒傷患者的營養處方箋時，其脂肪的給予應注意下列何者？', '["過多的脂肪易增加感染機率", "ω-6脂肪酸可增加管灌餵食的耐受性", "ω-3脂肪酸通常必須在燒傷初期給予，以增加免疫功能", "除去蛋白質熱量後，脂肪約占剩餘熱量的20%~30%"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "95191f7f2b97", "answer_pdf_sha1": "63031e3acdd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 12, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08795', 'dietitian', 'dietitian-moex-098-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關高血壓患者之SOAP敘述，下列何者錯誤？', '["S：陳先生，卡車司機，經常頭痛、頭暈、睡不著", "O：三次血壓160/90、175/95、177/92 mmHg", "A：醫師開給他diuretic、Lasix與Inderal，並給予無添加鹽飲食清單原則", "P：RD提供DASH飲食設計"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "95191f7f2b97", "answer_pdf_sha1": "63031e3acdd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 13, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08796', 'dietitian', 'dietitian-moex-098-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關心臟衰竭患者的營養醫療之敘述，下列何者錯誤？', '["鉀的限制量1000-2000 mg", "鈉的限制量，每天1200-2000 mg", "須視情況補充鎂", "水分的限制量，每天1000-2000 mL"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "95191f7f2b97", "answer_pdf_sha1": "63031e3acdd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 14, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08797', 'dietitian', 'dietitian-moex-098-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關atherosclerosis形成機轉之敘述，下列何者錯誤？', '["LDL是很重要的危險因子", "血管中過多游離的cholesterol會黏附在血管的內皮細胞，影響內皮細胞的功能", "內皮細胞的功能異常時，nitric oxide生成會減少，因此會影響血管舒張的功能", "發炎反應（inflammation）會加速atherosclerosis之形成"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "95191f7f2b97", "answer_pdf_sha1": "63031e3acdd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 15, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08798', 'dietitian', 'dietitian-moex-098-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '使用 Warfarin（Coumadin）藥物之心血管疾病患者，宜限制大量攝取下列何種營養素以避免營養與藥物 之交互作用？', '["Vitamin A", "Potassium", "Folic acid", "Vitamin K"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "95191f7f2b97", "answer_pdf_sha1": "63031e3acdd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 16, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
