  ('dietitian-moex-08801', 'dietitian', 'dietitian-moex-098-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關草酸鈣結石患者之飲食，下列何者錯誤？', '["應限制飲食中鈣質之攝取", "攝取足夠維生素B 可減少內生性草酸生成 6", "草酸含量高之飲料如茶、葡萄汁、橘子汁等應減少飲用", "不宜補充高量維生素C"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "95191f7f2b97", "answer_pdf_sha1": "63031e3acdd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 19, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
