  ('dietitian-moex-08803', 'dietitian', 'dietitian-moex-098-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關運動時對於糖尿病患的醣類需求之敘述，下列何者錯誤？', '["運動前，當血糖濃度小於100 mg/dL，須提供醣類攝取", "中度運動量，少於30分鐘時，不須增加任何醣類與胰島素", "中度運動量，每30-60分鐘時可提供30 g醣類", "若病人無胰島素治療，則不須補充醣類"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "95191f7f2b97", "answer_pdf_sha1": "63031e3acdd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 21, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
